import React, { useCallback, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Select,
  DateRangeFilter,
  SearchTextInput,
  dispatchAppToast,
  LinListFilterField,
  LinPageLayout,
  useViewMobileLayout,
} from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../store/hooks';
import { useProcessingLevelLabels } from '../../hooks/useProcessingLevelLabels';
import { useVoucherListFilterState } from '../../hooks/useVoucherListFilterState';
import { LIST_FILTER_SCOPE } from '../../constants/listFilterScopes';
import { ktService } from '../../services/kt/ktService';
import type { CashVoucherDto } from '../../services/kt/models';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import {
  VOUCHER_LIST_ROW_MENU_HINT_DESKTOP,
  VOUCHER_LIST_ROW_MENU_HINT_TOUCH,
  voucherListRowMenuHintDismissStorageKey,
} from '../../utils/voucherListRowMenuHint';
import { ProcessingLevelApproveModal } from '../voucher/ProcessingLevelApproveModal';
import { VoucherPrintModal, VoucherPostedLedgerModal } from '../voucher';
import { VoucherRowActionMenu, type VoucherRowMenuAction } from '../voucher-list';
import { useVoucherListSelection } from '../../hooks/useVoucherListSelection';
import { useVoucherListActions } from '../../hooks/useVoucherListActions';
import { canEditFromListRow, canViewLedgerFromListRow } from '../../utils/voucherListRowActions';
import { getCashVoucherConfig } from '../../features/kt/cash-voucher/shared/config/cashVoucherConfig';
import erp from '../../styles/erpPage.module.css';
import {
  DEFAULT_PAGE_SIZE,
  VoucherListPagination,
  type ListPageSize,
} from '../list/VoucherListPagination';
import { useVoucherListTableBusy } from '../list/useVoucherListTableBusy';
import {
  CatalogListGridFromSchema,
  ListUiSchemaEditorModal,
  listVisibleFields,
  useCatalogUiSchema,
} from '../listUiSchema';
import { LIST_UI_SCHEMA_KIND } from '../../types/catalogUiSchema';

const PAGE_SIZE = DEFAULT_PAGE_SIZE;
export type CashVoucherKind = 'receipt' | 'payment';

const CONFIG = {
  receipt: {
    title: 'Phiếu thu',
    listTitle: 'Danh sách phiếu thu',
    pageId: 'kt-phieu-thu',
    icon: 'fa-file-invoice-dollar',
    createPath: '/kt/pt/them',
    createInitFormName: 'create-cash-receipt',
    detailPath: (id: string) => `/kt/pt/${id}`,
    fetch: ktService.getReceipts,
    batchUpdateProcessingLevel: ktService.batchUpdateReceiptProcessingLevel,
    listScope: LIST_FILTER_SCOPE.phieuThu,
  },
  payment: {
    title: 'Phiếu chi',
    listTitle: 'Danh sách phiếu chi',
    pageId: 'kt-phieu-chi',
    icon: 'fa-money-bill-wave',
    createPath: '/kt/pc/them',
    createInitFormName: 'create-cash-payment',
    detailPath: (id: string) => `/kt/pc/${id}`,
    fetch: ktService.getPayments,
    batchUpdateProcessingLevel: ktService.batchUpdatePaymentProcessingLevel,
    listScope: LIST_FILTER_SCOPE.phieuChi,
  },
} as const;

function isRowSelectable(row: CashVoucherDto): boolean {
  return row.status === 'Draft';
}

export const CashVoucherList: React.FC<{ kind: CashVoucherKind }> = ({ kind }) => {
  const cfg = CONFIG[kind];
  const beCfg = getCashVoucherConfig(kind);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const viewMobile = useViewMobileLayout();
  const {
    initialized,
    fromDate,
    toDate,
    datePreset,
    applyDateRange,
    processingLevel,
    setProcessingLevel,
    searchDraft,
    setSearchDraft,
    search,
    setSearch,
    page,
    setPage,
    resetPage,
  } = useVoucherListFilterState(cfg.listScope);
  const [items, setItems] = useState<CashVoucherDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);
  const [pageSize, setPageSizeState] = useState<ListPageSize>(PAGE_SIZE);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [approving, setApproving] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [showSchemaEditor, setShowSchemaEditor] = useState(false);
  const [rowMenu, setRowMenu] = useState<{ x: number; y: number; row: CashVoucherDto } | null>(null);
  const testIdPrefix = kind === 'receipt' ? 'kt-phieu-thu' : 'kt-phieu-chi';
  const uiSchemaKind = kind === 'receipt'
    ? LIST_UI_SCHEMA_KIND.cashReceipt
    : LIST_UI_SCHEMA_KIND.cashPayment;
  const sampleRow = useMemo(
    () => (items[0] ? (items[0] as unknown as Record<string, unknown>) : null),
    [items],
  );
  const { schema, reload: reloadSchema } = useCatalogUiSchema(uiSchemaKind, { sampleRow });
  const listColumns = useMemo(() => listVisibleFields(schema), [schema]);
  const { levelOptions, filterOptions, formatLabel } = useProcessingLevelLabels(kind);
  const {
    formPermissions,
    canCreate,
    canApprove,
    canUpdate,
    canPrint,
    canViewLedger: canViewLedgerPerm,
  } = useVoucherListActions(cfg.createInitFormName);
  void formPermissions;
  const { showTableLoading, pulseSearch } = useVoucherListTableBusy(loading);

  const selection = useVoucherListSelection({
    rows: items,
    totalCount,
    page,
    pageSize,
    getRowId: r => r.id,
    isRowSelectable,
  });

  const activeRow = selection.activeRow;

  const canViewActive = Boolean(activeRow);
  const canEditActive = activeRow
    ? canEditFromListRow(activeRow, canUpdate)
    : false;
  const canViewLedgerActive = activeRow
    ? canViewLedgerFromListRow(activeRow, canViewLedgerPerm)
    : false;
  const canPrintActive = Boolean(activeRow) && canPrint;

  const refresh = useCallback(() => {
    selection.clearSelection();
    setReloadKey(k => k + 1);
  }, [selection]);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      setPage(1);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    });
  };

  const setPageSize = (size: number) => {
    setPageSizeState(size as ListPageSize);
    setPage(1);
    selection.clearSelection();
  };

  React.useEffect(() => {
    if (!initialized) return;
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      cfg.fetch({
        fromDate,
        toDate,
        search: search || undefined,
        processingLevel: processingLevel || undefined,
        page,
        pageSize,
      })
        .then(res => { if (!cancelled) { setItems(res.items); setTotalCount(res.totalCount); } })
        .catch(err => {
          if (!cancelled) {
            dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải danh sách'), type: 'error' });
          }
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [initialized, fromDate, toDate, search, processingLevel, page, pageSize, kind, reloadKey, dispatch, cfg]);

  const handleBatchApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      await cfg.batchUpdateProcessingLevel({
        ids: selection.selectedIdList,
        processingLevel: newLevel,
      });
      dispatchAppToast(dispatch, { message: 'Phê duyệt thành công', type: 'success' });
      setShowApproveModal(false);
      selection.clearSelection();
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(err, 'Phê duyệt thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  const navigateToRow = useCallback((id: string, startInEditMode?: boolean) => {
    navigate(cfg.detailPath(id), {
      state: startInEditMode ? { startInEditMode: true } : undefined,
    });
  }, [navigate, cfg]);

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const rowMenuHintMessage = viewMobile
    ? VOUCHER_LIST_ROW_MENU_HINT_TOUCH
    : VOUCHER_LIST_ROW_MENU_HINT_DESKTOP;

  const handleRowOpenActionMenu = useCallback(
    ({ row, x, y }: { row: CashVoucherDto; x: number; y: number }) => {
      selection.selectActiveRow(row);
      setRowMenu({ x, y, row });
    },
    [selection],
  );

  const handleRowMenuSelect = useCallback(
    (action: VoucherRowMenuAction) => {
      const row = rowMenu?.row;
      if (!row) return;
      switch (action) {
        case 'view':
          navigateToRow(row.id);
          break;
        case 'edit':
          if (canEditFromListRow(row, canUpdate)) {
            navigateToRow(row.id, true);
          }
          break;
        case 'viewLedger':
          if (canViewLedgerFromListRow(row, canViewLedgerPerm)) {
            setShowLedgerModal(true);
          }
          break;
        case 'print':
          if (canPrint) {
            setShowPrintModal(true);
          }
          break;
        default:
          break;
      }
    },
    [rowMenu?.row, canUpdate, canViewLedgerPerm, canPrint, navigateToRow],
  );

  const rowMenuRow = rowMenu?.row;
  const rowMenuShowEdit = rowMenuRow ? canEditFromListRow(rowMenuRow, canUpdate) : false;
  const rowMenuViewLedgerDisabled = rowMenuRow
    ? !canViewLedgerFromListRow(rowMenuRow, canViewLedgerPerm)
    : true;
  const rowMenuPrintDisabled = !canPrint;

  const voucherToolbar = useMemo(
    () => ({
      testIdPrefix,
      onRefresh: refresh,
      canApprove,
      approveDisabled: selection.selectedCount === 0,
      onApprove: () => setShowApproveModal(true),
      canViewLedger: canViewLedgerActive,
      onViewLedger: () => setShowLedgerModal(true),
      canPrint: canPrintActive,
      onPrint: () => setShowPrintModal(true),
      canView: canViewActive,
      onView: () => activeRow && navigateToRow(activeRow.id),
      canEdit: canEditActive,
      onEdit: () => activeRow && navigateToRow(activeRow.id, true),
      canCreate,
      onCreate: () => navigate(cfg.createPath),
      onEditConfig: () => setShowSchemaEditor(true),
    }),
    [
      testIdPrefix,
      canApprove,
      selection.selectedCount,
      canViewLedgerActive,
      canPrintActive,
      canViewActive,
      canEditActive,
      canCreate,
      activeRow,
      cfg.createPath,
      refresh,
      navigate,
      navigateToRow,
    ],
  );

  const filterItems = useMemo(
    () => [
      {
        testId: `${testIdPrefix}-field-search`,
        content: (
          <SearchTextInput
            label="Tìm kiếm"
            placeholder="Tìm số phiếu, đối tác, diễn giải..."
            value={searchDraft}
            onChange={setSearchDraft}
            onSearch={handleSearch}
            testId={`${testIdPrefix}-search-text`}
          />
        ),
      },
      {
        testId: `${testIdPrefix}-field-dateRange`,
        content: (
          <DateRangeFilter
            label="Thời gian"
            fullWidth
            testId={`${testIdPrefix}-date-range`}
            fromDate={fromDate}
            toDate={toDate}
            preset={datePreset}
            onChange={(v: DateRangeValue) => {
              applyDateRange(v.fromDate, v.toDate, v.preset);
              resetPage();
            }}
          />
        ),
      },
      {
        testId: `${testIdPrefix}-field-processingLevel`,
        content: (
          <Select
            label="Mức xử lý"
            value={processingLevel}
            onChange={e => { setProcessingLevel(e.target.value); resetPage(); }}
            options={filterOptions}
            fullWidth
          />
        ),
      },
    ],
    [
      testIdPrefix,
      searchDraft,
      fromDate,
      toDate,
      datePreset,
      processingLevel,
      filterOptions,
      applyDateRange,
      resetPage,
      setProcessingLevel,
      setSearchDraft,
      handleSearch,
    ],
  );

  const batchBar = selection.selectedCount > 0 ? (
    <div className={erp.batchBar} data-testid={`${testIdPrefix}-batch-bar`}>
      <span>Đã chọn {selection.selectedCount}</span>
      <button
        type="button"
        className={erp.batchBarLink}
        data-testid={`${testIdPrefix}-batch-clear`}
        onClick={selection.clearSelection}
      >
        Bỏ chọn tất cả
      </button>
    </div>
  ) : null;

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty}>Không có dữ liệu</div>
  ) : !showTableLoading && listColumns.length > 0 ? (
    <CatalogListGridFromSchema
      testIdPrefix={testIdPrefix}
      rows={items}
      page={page}
      pageSize={pageSize}
      columns={listColumns}
      schema={schema}
      selection={selection}
      getRowId={r => r.id}
      isRowSelectable={isRowSelectable}
      formatProcessingLevel={formatLabel}
      gridProps={{
        onRowOpenActionMenu: handleRowOpenActionMenu,
        rowMenuHintMessage,
        rowMenuHintDismissStorageKey: voucherListRowMenuHintDismissStorageKey(testIdPrefix),
        enableRowMenuLongPress: viewMobile,
      }}
    />
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      <LinPageLayout
        kind="voucher"
        testIdPrefix={testIdPrefix}
        pageId={cfg.pageId}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: cfg.title,
          titleIconClass: `fas ${cfg.icon}`,
          pageId: cfg.pageId,
        }}
        voucherToolbar={voucherToolbar}
        beforeToolbar={batchBar}
        listTitle={cfg.listTitle}
        listRowMenuHelp
        filterItems={filterItems}
        filterMaxWidthPx={1000}
        showTableLoading={showTableLoading}
        skeletonRows={Math.min(pageSize, 8)}
        footer={(
          <VoucherListPagination
            testIdPrefix={testIdPrefix}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={p => { setPage(p); selection.clearSelection(); }}
            onPageSizeChange={setPageSize}
          />
        )}
        modals={(
          <>
            <ProcessingLevelApproveModal
              isOpen={showApproveModal}
              onClose={() => setShowApproveModal(false)}
              currentLevel={String(levelOptions[0]?.value ?? '3')}
              levelOptions={levelOptions}
              onConfirm={handleBatchApproveConfirm}
              saving={approving}
              testIdPrefix={testIdPrefix}
            />
            {activeRow && (
              <>
                <VoucherPrintModal
                  isOpen={showPrintModal}
                  onClose={() => setShowPrintModal(false)}
                  voucherTitle={`${cfg.title} — ${activeRow.code}`}
                  onPrint={handlePrintConfirm}
                  printing={printing}
                  testIdPrefix={testIdPrefix}
                />
                <VoucherPostedLedgerModal
                  isOpen={showLedgerModal}
                  onClose={() => setShowLedgerModal(false)}
                  voucherTitle={`${cfg.title} — ${activeRow.code}`}
                  testIdPrefix={testIdPrefix}
                  fetchPostedLedger={() => beCfg.getPostedLedger(activeRow.id)}
                  fetchPostingStatus={() => beCfg.getPostingStatus(activeRow.id)}
                />
              </>
            )}
            <ListUiSchemaEditorModal
              testIdPrefix={testIdPrefix}
              catalogKind={uiSchemaKind}
              sampleRow={sampleRow}
              isOpen={showSchemaEditor}
              onClose={() => setShowSchemaEditor(false)}
              title="Cấu hình hiển thị danh sách"
              onSaved={() => {
                reloadSchema();
                refresh();
              }}
            />
            <VoucherRowActionMenu
              open={rowMenu != null}
              x={rowMenu?.x ?? 0}
              y={rowMenu?.y ?? 0}
              onClose={() => setRowMenu(null)}
              onSelect={handleRowMenuSelect}
              testIdPrefix={testIdPrefix}
              showView
              showEdit={rowMenuShowEdit}
              showViewLedger
              showPrint
              viewLedgerDisabled={rowMenuViewLedgerDisabled}
              printDisabled={rowMenuPrintDisabled}
            />
          </>
        )}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};
